transform_js:
var cats = ['A', 'B'];
var seriesData = cats.map(function(cat) {
  var vals = rawData.rows.filter(function(r) { return r.cat === cat; }).map(function(r) { return r.val; }).sort(function(a, b) { return a - b; });
  var min = vals[0];
  var max = vals[vals.length - 1];
  var step = (max - min) / 20;
  var density = [];
  for (var v = min; v <= max; v += step) {
    var count = 0;
    var bw = 2;
    for (var i = 0; i < vals.length; i++) {
      var u = (v - vals[i]) / bw;
      count += Math.exp(-0.5 * u * u) / (bw * Math.sqrt(2 * Math.PI));
    }
    density.push([v, count]);
  }
  return { name: cat, density: density };
});
transformedData = seriesData;

echarts_js:
var series = [];
var colors = ['#5470c6', '#ee6666'];
transformedData.forEach(function(sd, idx) {
  var maxD = 0;
  sd.density.forEach(function(d) { if (d[1] > maxD) maxD = d[1]; });
  var leftData = sd.density.map(function(d) { return [idx - d[1] / maxD * 0.4, d[0]]; });
  var rightData = sd.density.map(function(d) { return [idx + d[1] / maxD * 0.4, d[0]]; });
  rightData.reverse();
  var polygon = leftData.concat(rightData);
  series.push({ type: 'custom', renderItem: function(params, api) {
    if (params.dataIndex !== 0) return;
    var points = [];
    for (var i = 0; i < polygon.length; i++) {
      points.push(api.coord([polygon[i][0], polygon[i][1]]));
    }
    return { type: 'polygon', shape: { points: points }, style: { fill: colors[idx], opacity: 0.6 } };
  }, data: [0] });
});
option = { title: { text: 'Score Distribution (Violin)', left: 'center' }, tooltip: {}, xAxis: { type: 'value', min: -1, max: 2, axisLabel: { formatter: function(v) { return transformedData[Math.round(v)] ? transformedData[Math.round(v)].name : ''; } } }, yAxis: { type: 'value', name: 'Value' }, series: series };
